window._L = ['en','el','it','tr','ro','sq','bg','es','fr'];
window._ = {};

function _get(key) {
  var arr = window._[key];
  if (!arr) return key;
  var lang = localStorage.getItem('lang') || 'en';
  var idx = window._L.indexOf(lang);
  if (idx === -1) idx = 0;
  return arr[idx] || arr[0] || key;
}

window.__ = function(el) {
  var key = el.getAttribute('data-i18n');
  if (!key) return;
  var txt = _get(key);
  // replace only text nodes, preserve child elements
  var children = Array.from(el.childNodes);
  var textNodes = children.filter(function(n) { return n.nodeType === 3; });
  if (textNodes.length > 0) {
    textNodes[0].textContent = txt;
    // remove extra text nodes
    for (var i = 1; i < textNodes.length; i++) textNodes[i].textContent = '';
  } else {
    // If no text node, try textContent fallback but preserve icons
    if (el.children.length === 0) {
      el.textContent = txt;
    } else {
      // mixed content: find or create text node
      var tn = document.createTextNode(txt);
      el.insertBefore(tn, el.firstChild);
    }
  }
};

window.translatePage = function(lang) {
  localStorage.setItem('lang', lang);
  document.querySelectorAll('[data-i18n]').forEach(window.__);
  document.documentElement.lang = lang;
  // update typing animation if it exists
  if (window.restartTyping) window.restartTyping();
};

